#include <vector>
#include <queue>
#include <climits>

using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));
    dist[0][0][1] = 1;

    priority_queue<tuple<long long, long long, long long, long long>, vector<tuple<long long, long long, long long, long long>>, greater<tuple<long long, long long, long long, long long>>> pq;
    pq.push({1, 0, 0, 1});

    while (!pq.empty()) {
        auto [current_cost, i, j, p] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (current_cost > dist[i][j][p]) {
            continue;
        }

        if (p == 1) {
            if (j + 1 < n) {
                long long ni = i, nj = j + 1;
                long long new_p = 0;
                long long new_cost = current_cost + (ni + 1) * (nj + 1);
                if (new_cost < dist[ni][nj][new_p]) {
                    dist[ni][nj][new_p] = new_cost;
                    pq.push({new_cost, ni, nj, new_p});
                }
            }
            if (i + 1 < m) {
                long long ni = i + 1, nj = j;
                long long new_p = 0;
                long long new_cost = current_cost + (ni + 1) * (nj + 1);
                if (new_cost < dist[ni][nj][new_p]) {
                    dist[ni][nj][new_p] = new_cost;
                    pq.push({new_cost, ni, nj, new_p});
                }
            }
        } else {
            long long new_p = 1;
            long long new_cost = current_cost + waitCost[i][j];
            if (new_cost < dist[i][j][new_p]) {
                dist[i][j][new_p] = new_cost;
                pq.push({new_cost, i, j, new_p});
            }
        }
    }

    return -1;
}
